    public List<HistoryRecordedEventResponse> getHistoryRecordedEvents(
            TransactionReceipt transactionReceipt) {
        List<Contract.EventValuesWithLog> valueList = extractEventParametersWithLog(HISTORYRECORDED_EVENT, transactionReceipt);
        ArrayList<HistoryRecordedEventResponse> responses = new ArrayList<HistoryRecordedEventResponse>(valueList.size());
        for (Contract.EventValuesWithLog eventValues : valueList) {
            HistoryRecordedEventResponse typedResponse = new HistoryRecordedEventResponse();
            typedResponse.log = eventValues.getLog();
            typedResponse.receiptId = (byte[]) eventValues.getIndexedValues().get(0).getValue();
            typedResponse.operationType = (BigInteger) eventValues.getIndexedValues().get(1).getValue();
            typedResponse.operatorHash = (byte[]) eventValues.getNonIndexedValues().get(0).getValue();
            typedResponse.timestamp = (BigInteger) eventValues.getNonIndexedValues().get(1).getValue();
            typedResponse.blockNumber = (BigInteger) eventValues.getNonIndexedValues().get(2).getValue();
            responses.add(typedResponse);
        }
        return responses;
    }

    public void subscribeHistoryRecordedEvent(BigInteger fromBlock, BigInteger toBlock,
            List<String> otherTopics, EventSubCallback callback) {
        String topic0 = eventEncoder.encode(HISTORYRECORDED_EVENT);
        subscribeEvent(topic0,otherTopics,fromBlock,toBlock,callback);
    }

    public void subscribeHistoryRecordedEvent(EventSubCallback callback) {
        String topic0 = eventEncoder.encode(HISTORYRECORDED_EVENT);
        subscribeEvent(topic0,callback);
    }

